import React, { useState, useRef } from 'react';
import {
  Box,
  Button,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  IconButton,
  Typography,
  TextField,
  Tab,
  Tabs,
  Input,
} from '@mui/material';
import {
  Videocam as VideocamIcon,
  Stop as StopIcon,
  Upload as UploadIcon,
  Close as CloseIcon,
} from '@mui/icons-material';
import { videos } from '../utils/api';

const VideoRecorder = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [recordedBlob, setRecordedBlob] = useState(null);
  const [previewUrl, setPreviewUrl] = useState('');
  const mediaRecorderRef = useRef(null);
  const videoRef = useRef(null);
  const streamRef = useRef(null);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: true,
        audio: true,
      });
      streamRef.current = stream;
      videoRef.current.srcObject = stream;

      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;

      const chunks = [];
      mediaRecorder.ondataavailable = (e) => chunks.push(e.data);
      mediaRecorder.onstop = () => {
        const blob = new Blob(chunks, { type: 'video/webm' });
        setRecordedBlob(blob);
        setPreviewUrl(URL.createObjectURL(blob));
        streamRef.current.getTracks().forEach(track => track.stop());
        videoRef.current.srcObject = null;
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (error) {
      console.error('Error accessing camera:', error);
      alert('Could not access camera. Please check permissions.');
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const uploadVideo = async () => {
    if (!recordedBlob) return;

    const formData = new FormData();
    formData.append('video', recordedBlob, 'recorded-video.webm');
    formData.append('title', 'Recorded Video');
    formData.append('description', 'Video recorded from webcam');

    try {
      await videos.uploadVideo(formData);
      handleClose();
      alert('Video uploaded successfully!');
    } catch (error) {
      console.error('Error uploading video:', error);
      alert('Failed to upload video. Please try again.');
    }
  };

  const handleClose = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }
    if (videoRef.current) {
      videoRef.current.srcObject = null;
    }
    setIsRecording(false);
    setRecordedBlob(null);
    setPreviewUrl('');
    setIsOpen(false);
  };

  return (
    <>
      <Button
        variant="contained"
        color="primary"
        startIcon={<VideocamIcon />}
        onClick={() => setIsOpen(true)}
      >
        Record Video
      </Button>

      <Dialog
        open={isOpen}
        onClose={handleClose}
        maxWidth="md"
        fullWidth
      >
        <DialogTitle>
          Record Video
          <IconButton
            onClick={handleClose}
            sx={{ position: 'absolute', right: 8, top: 8 }}
          >
            <CloseIcon />
          </IconButton>
        </DialogTitle>
        <DialogContent>
          <Box sx={{ position: 'relative', minHeight: 400 }}>
            <video
              ref={videoRef}
              autoPlay
              muted
              style={{
                width: '100%',
                height: '400px',
                backgroundColor: '#000',
                display: !previewUrl ? 'block' : 'none'
              }}
            />
            {previewUrl && (
              <video
                src={previewUrl}
                controls
                style={{ width: '100%', height: '400px' }}
              />
            )}
            {!isRecording && !previewUrl && (
              <Typography
                variant="body1"
                sx={{
                  position: 'absolute',
                  top: '50%',
                  left: '50%',
                  transform: 'translate(-50%, -50%)',
                  color: '#fff'
                }}
              >
                Click Record to start
              </Typography>
            )}
          </Box>
        </DialogContent>
        <DialogActions>
          {!isRecording && !previewUrl && (
            <Button
              onClick={startRecording}
              variant="contained"
              color="primary"
              startIcon={<VideocamIcon />}
            >
              Record
            </Button>
          )}
          {isRecording && (
            <Button
              onClick={stopRecording}
              variant="contained"
              color="error"
              startIcon={<StopIcon />}
            >
              Stop
            </Button>
          )}
          {previewUrl && (
            <>
              <Button
                onClick={startRecording}
                variant="outlined"
                startIcon={<VideocamIcon />}
              >
                Record Again
              </Button>
              <Button
                onClick={uploadVideo}
                variant="contained"
                color="primary"
                startIcon={<UploadIcon />}
              >
                Upload
              </Button>
            </>
          )}
        </DialogActions>
      </Dialog>
    </>
  );
};

export default VideoRecorder;
